// MetricsPage collects data and returns the metrics overview page component.
func MetricsPage(ctx context.Context, c *collector.DataCollector, h *collector.DataHistory, basePath string) (templ.Component, error) {
	report := c.CollectMetricsReport(ctx)
	metricsData := c.CollectMetrics(ctx)

	// Build chart data
	typeChart := buildMetricsTypeChartData(report.MetricsByType)

	metricsSnapshots := h.GetMetrics()
	trendChart := buildMetricsHistoryChartData(metricsSnapshots)
	hasHistory := hasMetricsSnapshots(metricsSnapshots)

	// Select most recent 15 metrics for the overview
	recentMetrics := recentMetricsSlice(report.TopMetrics, 15)

	return MetricsPageContent(report, metricsData, typeChart, trendChart, hasHistory, recentMetrics, basePath), nil
}

// AllMetricsPage collects data and returns the full metrics list page component.
func AllMetricsPage(ctx context.Context, c *collector.DataCollector, basePath string) (templ.Component, error) {
	report := c.CollectMetricsReport(ctx)
	return AllMetricsPageContent(report.TopMetrics, basePath), nil
}

